const staticData = $getWorkflowStaticData('global');
const offset = staticData.lastUpdateId ? staticData.lastUpdateId + 1 : 0;
return [{ json: { offset: offset } }];

const updates = $input.first().json.result;
const staticData = $getWorkflowStaticData('global');

if (!updates || updates.length === 0) return [];

const TOKEN = 'YOUR_TELEGRAM_BOT_TOKEN';
const API = `https://api.telegram.org/bot${TOKEN}`;

async function sendMsg(chatId, text, withButton = false) {
  const body = { chat_id: chatId, text };
  if (withButton) {
    body.reply_markup = {
      inline_keyboard: [[{ text: '开始处理 / Start ✅', callback_data: 'start' }]]
    };
  }
  await this.helpers.httpRequest({
    method: 'POST', url: `${API}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body, json: true
  });
}

const dispatchItems = [];
let maxProcessedUpdateId = staticData.lastUpdateId || 0;

for (const update of updates) {
  try {
    // ── 用户点了按钮 ──
    if (update.callback_query) {
      const cb = update.callback_query;
      const chatId = cb.message.chat.id;

      try {
        await this.helpers.httpRequest({
          method: 'POST', url: `${API}/answerCallbackQuery`,
          headers: { 'Content-Type': 'application/json' },
          body: { callback_query_id: cb.id, text: '⏳ 收到' },
          json: true
        });
      } catch (e) { /* callback过期，忽略 */ }

      if (cb.data && cb.data.startsWith('rate_')) {
        const stars = cb.data.replace('rate_', '');
        await sendMsg.call(this, chatId, `🙏 谢谢你的评价（${stars}⭐）！有什么想让我改进的，直接打字告诉我就行。`);
        maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
        continue;
      }

      if (cb.data === 'start') {
        const queue = staticData[`queue_${chatId}`] || [];
        if (queue.length === 0) {
          await sendMsg.call(this, chatId, '❌ 没有待处理的菜单，请先发送菜单图片、PDF或文字。');
        } else {
          const caption = staticData[`caption_${chatId}`] || '';
          await sendMsg.call(this, chatId, `⏳ 正在处理 ${queue.length} 个文件，请稍等...`);
          for (const item of queue) {
            item.caption = caption;
            dispatchItems.push(item);
          }
          delete staticData[`queue_${chatId}`];
          delete staticData[`caption_${chatId}`];
          staticData[`awaitingFeedback_${chatId}`] = true;
        }
      }
      maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
      continue;
    }

    const msg = update.message;
    if (!msg) {
      maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
      continue;
    }
    const chatId = msg.chat.id;

    // ── 照片 ──
    if (msg.photo) {
      const photo = msg.photo[msg.photo.length - 1];
      if (!staticData[`queue_${chatId}`]) staticData[`queue_${chatId}`] = [];
      staticData[`queue_${chatId}`].push({
        update_id: update.update_id,
        chat_id: chatId,
        file_id: photo.file_id,
        caption: '',
        mime_type: 'image/jpeg'
      });
      const count = staticData[`queue_${chatId}`].length;
      await sendMsg.call(this, chatId,
        `📥 已收到菜单图片（队列共 ${count} 个）\n\n有需要特别注意的吗？（分类、规格、外带加价等）\n直接回复我，或者没有的话按下面按钮直接开始。`,
        true
      );
      maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
      continue;
    }

    // ── PDF ──
    if (msg.document && msg.document.mime_type === 'application/pdf') {
      if (msg.document.file_size > 20971520) {
        const sizeMB = (msg.document.file_size / 1024 / 1024).toFixed(1);
        await sendMsg.call(this, chatId,
          `⚠️ PDF文件（${sizeMB}MB）超过20MB限制。\n\n请先压缩：https://www.ilovepdf.com/compress_pdf\n压缩后重新发给我。`
        );
        maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
        continue;
      }
      if (!staticData[`queue_${chatId}`]) staticData[`queue_${chatId}`] = [];
      staticData[`queue_${chatId}`].push({
        update_id: update.update_id,
        chat_id: chatId,
        file_id: msg.document.file_id,
        caption: '',
        mime_type: 'application/pdf'
      });
      const count = staticData[`queue_${chatId}`].length;
      await sendMsg.call(this, chatId,
        `📥 已收到PDF菜单（队列共 ${count} 个）\n\n有需要特别注意的吗？（分类、规格、外带加价等）\n直接回复我，或者没有的话按下面按钮直接开始。`,
        true
      );
      maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
      continue;
    }

    // ── 文字 ──
    if (msg.text) {
      const text = msg.text.trim();
      const lower = text.toLowerCase();

      if (lower === '开始' || lower === 'start' || lower === '/go') {
        const queue = staticData[`queue_${chatId}`] || [];
        if (queue.length === 0) {
          await sendMsg.call(this, chatId, '❌ 没有待处理的菜单，请先发送菜单图片、PDF或文字。');
        } else {
          const caption = staticData[`caption_${chatId}`] || '';
          await sendMsg.call(this, chatId, `⏳ 正在处理 ${queue.length} 个文件，请稍等...`);
          for (const item of queue) {
            item.caption = caption;
            dispatchItems.push(item);
          }
          delete staticData[`queue_${chatId}`];
          delete staticData[`caption_${chatId}`];
          staticData[`awaitingFeedback_${chatId}`] = true;
        }
        maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
        continue;
      }

      // 队列非空 → 当备注（优先级最高，避免被反馈逻辑抢走）
      if (staticData[`queue_${chatId}`] && staticData[`queue_${chatId}`].length > 0) {
        staticData[`caption_${chatId}`] = text;
        await sendMsg.call(this, chatId,
          `✏️ 备注已记录：「${text}」\n\n准备好了就按开始处理。`,
          true
        );
        maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
        continue;
      }

      // 队列空 且 正在等反馈 → 当反馈
      if (staticData[`awaitingFeedback_${chatId}`]) {
        delete staticData[`awaitingFeedback_${chatId}`];
        await sendMsg.call(this, chatId, '✅ 收到你的反馈了，谢谢！我会记住这个改进点。');
        maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
        continue;
      }

      // 都不是 → 当新菜单文字
      if (!staticData[`queue_${chatId}`]) staticData[`queue_${chatId}`] = [];
      staticData[`queue_${chatId}`].push({
        update_id: update.update_id,
        chat_id: chatId,
        file_id: null,
        caption: '',
        mime_type: 'text/plain',
        text_content: text
      });
      await sendMsg.call(this, chatId,
        `📥 已收到菜单文字内容。\n\n有需要特别注意的吗？\n没有的话按下面按钮直接开始。`,
        true
      );
      maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
      continue;
    }

    maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);

  } catch (err) {
    maxProcessedUpdateId = Math.max(maxProcessedUpdateId, update.update_id);
    try {
      const failedChatId = update.callback_query?.message?.chat?.id || update.message?.chat?.id;
      if (failedChatId) {
        await sendMsg.call(this, failedChatId, `⚠️ 处理消息时出错：${err.message}\n请重试一次。`);
      }
    } catch (e) { /* ignore */ }
  }
}

staticData.lastUpdateId = maxProcessedUpdateId;

return dispatchItems.map(item => ({ json: item }));
